mapper.select:
SELECT cache_no AS cacheNo, tmdb_id AS tmdbId, media_type AS mediaType, season_no AS seasonNo, source_type AS sourceType, video_key AS videoKey, video_name AS videoName, video_site AS videoSite, video_type AS videoType, display_order AS displayOrder, reg_date AS regDate FROM media_video_cache WHERE media_type = #{mediaType} AND tmdb_id = #{tmdbId}
AND season_no = #{seasonNo}
AND season_no IS NULL
ORDER BY display_order ASC, cache_no ASC

